#include <stdio.h>
#define BROJ_REDOVA 4
#define BROJ_KOLONA 5

int main() {
    int i, j;
    int matrica[BROJ_REDOVA][BROJ_KOLONA];
    int temp[BROJ_REDOVA][BROJ_KOLONA]; /* privremena kopija matrice */

    printf("Unesite elemente matrice 4x5:\n");
    for (i = 0; i < BROJ_REDOVA; i++)
        for (j = 0; j < BROJ_KOLONA; j++) {
            scanf("%d", &matrica[i][j]);
            temp[i][j] = matrica[i][j];
        }

    /* Zamjena kolona dva mjesta desno (cirkularno) */
    for (j = 0; j < BROJ_KOLONA; j++) {
        for (i = 0; i < BROJ_REDOVA; i++)
            matrica[i][(j + 2) % BROJ_KOLONA] = temp[i][j];
    }

    printf("Matrica nakon zamjene kolona:\n");
    for (i = 0; i < BROJ_REDOVA; i++) {
        for (j = 0; j < BROJ_KOLONA; j++)
            printf("%d ", matrica[i][j]);
        printf("\n");
    }

    return 0;
}
